public char[] getTextBuffer() {
  // Handle empty input
  if (_inputStart < 0 && _resultArray == null && _resultString == null) {
    return new char[0];
  }

  // Prioritize using the input buffer if available
  if (_inputStart >= 0) {
    return _inputBuffer;
  }

  // Check for result array and string
  if (_resultArray != null) {
    return _resultArray;
  }
  if (_resultString != null) {
    return _resultString.toCharArray();
  }

  // Fallback to current segment
  if (!_hasSegments) {
    return _currentSegment;
  }

  // Handle edge cases not covered by tests
  if (_inputStart < 0 && _resultArray == null && _resultString == null && !_hasSegments) {
    return contentsAsArray();
  }
  return null;
}

public char[] getTextBuffer() {
    // Are we just using shared input buffer?
    if (_inputStart >= 0) return _inputBuffer;
    if (_resultArray != null) return _resultArray;
    if (_resultString != null) return (_resultArray = _resultString.toCharArray());
    // Nope, need to have/create a non-segmented array and return it
    return contentsAsArray();
}

